import{_ as t,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Safety/user-rate-limits.md","filePath":"bn-BD/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"bn-BD/Safety/user-rate-limits.md"};function o(p,e,n,u,c,m){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits control করে regular users বা visitors homepage থেকে কত ঘন ঘন files upload করতে পারবে। Public upload pages abuse হওয়া ঠেকাতে এটি সাহায্য করে।</p><p>এই feature শুধু homepage uploads-এ প্রভাব ফেলে। Admin uploads এবং API Tokens দিয়ে করা uploads user rate limits দ্বারা সীমাবদ্ধ নয়।</p><h2 id="কোথায়-configure-করবেন" tabindex="-1">কোথায় Configure করবেন <a class="header-anchor" href="#কোথায়-configure-করবেন" aria-label="Permalink to &quot;কোথায় Configure করবেন&quot;">​</a></h2><p>Admin panel খুলে যান:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+t+'" alt="User rate limit settings" loading="lazy"></p><h2 id="rate-limits-enable-করা" tabindex="-1">Rate Limits Enable করা <a class="header-anchor" href="#rate-limits-enable-করা" aria-label="Permalink to &quot;Rate Limits Enable করা&quot;">​</a></h2><p><code>Enable Rate Limits</code> চালু করলে ImgBed uploader IP address অনুযায়ী recent uploads track করে।</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>কত সময় পেছনের upload records count হবে।</td></tr><tr><td>Max file count</td><td>20</td><td>Detection window-এ allowed maximum file count।</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>একটি file-এর maximum size।</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Detection window-এ maximum total upload size।</td></tr></tbody></table><p>যেমন, 1.5 hour window, 20 files, প্রতি file 20 MB এবং মোট 200 MB থাকলে same IP থেকে uploads কোনো configured limit ছাড়ালেই block হবে।</p><h2 id="file-types-exclude-করা" tabindex="-1">File Types Exclude করা <a class="header-anchor" href="#file-types-exclude-করা" aria-label="Permalink to &quot;File Types Exclude করা&quot;">​</a></h2><p><code>Excluded upload file types</code> regular users বা visitors-কে selected file categories upload করা থেকে আটকায়।</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif এবং similar image files</td></tr><tr><td>Videos</td><td>mp4, webm, mov এবং similar video files</td></tr><tr><td>Audio</td><td>mp3, flac, wav এবং similar audio files</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx এবং similar document files</td></tr><tr><td>Other</td><td>ওপরের categories-এর বাইরে files, যেমন zip, rar, exe, apk</td></tr></tbody></table><p>Default-এ কোনো type selected থাকে না, অর্থাৎ সেটি allowed।</p><p>কোনো type-এ click করলে সেটি highlight হয়, যার মানে সেই type blocked।</p><p><code>Other</code> selected থাকলে zip বা rar upload করা visitors block হবে এবং জানানো হবে যে এই file type supported নয়।</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>Limit trigger হলে users matching message দেখে:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>File খুব বড়; upload-এর আগে compress করা উচিত।</td></tr><tr><td>File type blocked</td><td>এই file type supported নয়। সরিয়ে আবার চেষ্টা করুন।</td></tr><tr><td>Uploads too frequent</td><td>Recent uploads খুব frequent; retry time দেখানো হবে।</td></tr><tr><td>Total size too high</td><td>Recent total upload size খুব বেশি; retry time দেখানো হবে।</td></tr></tbody></table><h2 id="কখন-enable-করবেন" tabindex="-1">কখন Enable করবেন <a class="header-anchor" href="#কখন-enable-করবেন" aria-label="Permalink to &quot;কখন Enable করবেন&quot;">​</a></h2><p>আপনার upload homepage publicly accessible হলে user rate limits enable করুন।</p><p>Common reasons:</p><ul><li>Scripted bulk uploads নিয়ে চিন্তা আছে।</li><li>Visitor uploads-এর large files limit করতে চান।</li><li>Regular users যেন শুধু images upload করে, archives বা installers নয়।</li><li>Public upload available রাখতে চান, কিন্তু resource usage control করতে চান।</li></ul><p>Site শুধু নিজের জন্য হলে, বা শুধু administrators upload করলে এটি disabled রাখতে পারেন।</p>',28)])])}const f=i(r,[["render",o]]);export{g as __pageData,f as default};
